class Solution:
  def minimumCost(self, n: int, costs: list[int]) -> int:
    dp = [0] * n
    for i in range(1, n):
      if costs[i] > costs[i - 1]:
        dp[i] = dp[i - 1] + costs[i]
      else:
        dp[i] = dp[i - 1] + min(costs[i], costs[i - 1])
    return dp[-1]

