class Solution {
  public:
    long long minimumCost(int n, vector<int>& costs) {
      long long dp[n];
      dp[0] = costs[0];
      for (int i = 1; i < n; ++i) {
        if (costs[i] > costs[i - 1])
          dp[i] = dp[i - 1] + costs[i];
        else
          dp[i] = dp[i - 1] + min(costs[i], costs[i - 1]);
      }
      return dp[n - 1];
    }
};
